    HWND hWnd = CreateWindowExW(0, L"ExploitClass", L"", WS_OVERLAPPEDWINDOW,
        0, 0, 100, 100, NULL, NULL, GetModuleHandle(NULL), NULL);

    // 后续利用：通过SetWindowLong等修改堆内容
